#
# bash recipes/python/gflownet_gata2.sh
#
python -m docker_entrypoint \
    --model bpnet \
        --protein 'GATA2' \
    --optimization gflownet \
        --beta 2.0 \
        --learning_rate 1e-3 \
        --batch_size 32 \
        --hidden_dim 128 \
        --rnd_seed 0 \
    --max_seconds 240 \
    --optimization_steps_per_output 5 \
    --proposals_per_round 2 \
    --output_format csv \
    --output_path ./output/python_recipe/gflownet_gata2 \
    --start_sequence 
